from flask import Flask, request, jsonify
import psycopg2
from psycopg2 import sql, extras
import re
from functools import wraps
import os

app = Flask(__name__)

DB_CONFIG = {
    'host': os.getenv('DB_HOST', 'localhost'),
    'port': os.getenv('DB_PORT', '5432'),
    'database': os.getenv('DB_NAME', 'analytics_db'),
    'user': os.getenv('DB_USER', 'postgres'),
    'password': os.getenv('DB_PASSWORD', 'password')
}

ALLOWED_TABLES = os.getenv('ALLOWED_TABLES', 'users,orders,products,transactions,analytics').split(',')
MAX_LIMIT = int(os.getenv('MAX_LIMIT', '1000'))

def get_db_connection():
    return psycopg2.connect(**DB_CONFIG)

def validate_identifier(identifier):
    if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', identifier):
        raise ValueError(f"Invalid identifier: {identifier}")
    return identifier

def validate_table_name(table_name):
    validate_identifier(table_name)
    if table_name not in ALLOWED_TABLES:
        raise ValueError(f"Table '{table_name}' is not allowed")
    return table_name

def handle_errors(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        try:
            return f(*args, **kwargs)
        except ValueError as e:
            return jsonify({'error': str(e)}), 400
        except psycopg2.Error as e:
            return jsonify({'error': f'Database error: {str(e)}'}), 500
        except Exception as e:
            return jsonify({'error': f'Internal server error: {str(e)}'}), 500
    return decorated_function

def build_where_clause(filters):
    if not filters:
        return sql.SQL(""), []
    
    conditions = []
    params = []
    
    for filter_item in filters:
        column = validate_identifier(filter_item.get('column'))
        operator = filter_item.get('operator', '=').upper()
        value = filter_item.get('value')
        
        allowed_operators = {
            '=': sql.SQL('='),
            '!=': sql.SQL('!='),
            '>': sql.SQL('>'),
            '<': sql.SQL('<'),
            '>=': sql.SQL('>='),
            '<=': sql.SQL('<='),
            'LIKE': sql.SQL('LIKE'),
            'ILIKE': sql.SQL('ILIKE'),
            'IN': sql.SQL('IN'),
            'NOT IN': sql.SQL('NOT IN'),
            'IS NULL': sql.SQL('IS NULL'),
            'IS NOT NULL': sql.SQL('IS NOT NULL')
        }
        
        if operator not in allowed_operators:
            raise ValueError(f"Invalid operator: {operator}")
        
        if operator in ['IS NULL', 'IS NOT NULL']:
            conditions.append(
                sql.SQL("{} {}").format(
                    sql.Identifier(column),
                    allowed_operators[operator]
                )
            )
        elif operator in ['IN', 'NOT IN']:
            if not isinstance(value, list):
                raise ValueError(f"Value for {operator} must be a list")
            placeholders = sql.SQL(', ').join([sql.Placeholder()] * len(value))
            conditions.append(
                sql.SQL("{} {} ({})").format(
                    sql.Identifier(column),
                    allowed_operators[operator],
                    placeholders
                )
            )
            params.extend(value)
        else:
            conditions.append(
                sql.SQL("{} {} {}").format(
                    sql.Identifier(column),
                    allowed_operators[operator],
                    sql.Placeholder()
                )
            )
            params.append(value)
    
    where_clause = sql.SQL(" WHERE ") + sql.SQL(" AND ").join(conditions)
    return where_clause, params

def build_order_clause(order_by):
    if not order_by:
        return sql.SQL("")
    
    order_parts = []
    for order_item in order_by:
        column = validate_identifier(order_item.get('column'))
        direction = order_item.get('direction', 'ASC').upper()
        
        if direction not in ['ASC', 'DESC']:
            raise ValueError(f"Invalid order direction: {direction}")
        
        order_parts.append(
            sql.SQL("{} {}").format(
                sql.Identifier(column),
                sql.SQL(direction)
            )
        )
    
    return sql.SQL(" ORDER BY ") + sql.SQL(", ").join(order_parts)

@app.route('/api/query', methods=['POST'])
@handle_errors
def query_data():
    data = request.get_json()
    
    if not data:
        return jsonify({'error': 'No data provided'}), 400
    
    table_name = validate_table_name(data.get('table'))
    columns = data.get('columns', ['*'])
    filters = data.get('filters', [])
    order_by = data.get('order_by', [])
    limit = min(data.get('limit', 100), MAX_LIMIT)
    offset = data.get('offset', 0)
    
    if columns != ['*']:
        columns = [validate_identifier(col) for col in columns]
        select_clause = sql.SQL(", ").join([sql.Identifier(col) for col in columns])
    else:
        select_clause = sql.SQL("*")
    
    where_clause, params = build_where_clause(filters)
    order_clause = build_order_clause(order_by)
    
    query = sql.SQL("SELECT {} FROM {}{}{}").format(
        select_clause,
        sql.Identifier(table_name),
        where_clause,
        order_clause
    )
    
    if limit:
        query = sql.SQL("{} LIMIT {} OFFSET {}").format(
            query,
            sql.Literal(limit),
            sql.Literal(offset)
        )
    
    conn = get_db_connection()
    try:
        with conn.cursor(cursor_factory=extras.RealDictCursor) as cur:
            cur.execute(query, params)
            results = cur.fetchall()
            
            return jsonify({
                'success': True,
                'data': results,
                'count': len(results),
                'limit': limit,
                'offset': offset
            })
    finally:
        conn.close()

