@handle_errors
def aggregate_data():
    data = request.get_json()
    
    if not data:
        return jsonify({'error': 'No data provided'}), 400
    
    table_name = validate_table_name(data.get('table'))
    aggregations = data.get('aggregations', [])
    group_by = data.get('group_by', [])
    filters = data.get('filters', [])
    having = data.get('having', [])
    order_by = data.get('order_by', [])
    limit = min(data.get('limit', 100), MAX_LIMIT)
    
    if not aggregations:
        return jsonify({'error': 'No aggregations specified'}), 400
    
    allowed_functions = ['COUNT', 'SUM', 'AVG', 'MIN', 'MAX']
    
    select_parts = []
    for agg in aggregations:
        func = agg.get('function', '').upper()
        column = agg.get('column', '*')
        alias = agg.get('alias')
        
        if func not in allowed_functions:
            raise ValueError(f"Invalid aggregation function: {func}")
        
        if column != '*':
            column = validate_identifier(column)
            agg_expr = sql.SQL("{}({})").format(
                sql.SQL(func),
                sql.Identifier(column)
            )
        else:
            agg_expr = sql.SQL("{}(*)").format(sql.SQL(func))
        
        if alias:
            alias = validate_identifier(alias)
            agg_expr = sql.SQL("{} AS {}").format(agg_expr, sql.Identifier(alias))
        
        select_parts.append(agg_expr)
    
    if group_by:
        group_by_validated = [validate_identifier(col) for col in group_by]
        for col in group_by_validated:
            select_parts.insert(0, sql.Identifier(col))
    
    select_clause = sql.SQL(", ").join(select_parts)
    where_clause, where_params = build_where_clause(filters)
    
    query = sql.SQL("SELECT {} FROM {}{}").format(
        select_clause,
        sql.Identifier(table_name),
        where_clause
    )
    
    params = where_params
    
    if group_by:
        group_clause = sql.SQL(" GROUP BY ") + sql.SQL(", ").join(
            [sql.Identifier(col) for col in group_by_validated]
        )
        query = sql.SQL("{}{}").format(query, group_clause)
    
    if having:
        having_clause, having_params = build_where_clause(having)
        having_clause = sql.SQL(having_clause.as_string(None).replace('WHERE', 'HAVING'))
        query = sql.SQL("{}{}").format(query, having_clause)
        params.extend(having_params)
    
    order_clause = build_order_clause(order_by)
    query = sql.SQL("{}{}").format(query, order_clause)
    
    if limit:
        query = sql.SQL("{} LIMIT {}").format(query, sql.Literal(limit))
    
    conn = get_db_connection()
    try:
        with conn.cursor(cursor_factory=extras.RealDictCursor) as cur:
            cur.execute(query, params)
            results = cur.fetchall()
            
            return jsonify({
                'success': True,
                'data': results,
                'count': len(results)
            })
    finally:
        conn.close()

